            } else if (token == "*" || token == "/") {
                // Differentiate product or quotient rule
                result += "a*b + b*a";
            } else {
                result += token; // Keep operator
            }
        } else {
            // Handle function
            result += "f'(x)";
        }
    }
    return result;
